var prompt = 'You are an expert SEO strategist. Generate a comprehensive list of SEO seed keywords based on the following business profile.\n\n';
prompt += 'BUSINESS NICHE: ' + $.input.businessNiche + '\n';
prompt += 'IDEAL CUSTOMER PROFILE: ' + $.input.idealCustomer + '\n';
if ($.input.competitors) {
  prompt += 'COMPETITORS: ' + $.input.competitors + '\n';
}
prompt += '\nINSTRUCTIONS:\n';
prompt += '- Generate 20-30 seed keywords across different intent categories\n';
prompt += '- Include informational, navigational, commercial, and transactional keywords\n';
prompt += '- Group by search intent\n';
prompt += '- Estimate difficulty and potential traffic for each\n';
prompt += '- Suggest long-tail variations for each seed keyword\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "keywords": [\n';
prompt += '    {\n';
prompt += '      "keyword": "...",\n';
prompt += '      "intent": "Informational|Navigational|Commercial|Transactional",\n';
prompt += '      "difficulty": "Low|Medium|High",\n';
prompt += '      "trafficPotential": "Low|Medium|High",\n';
prompt += '      "priority": 1,\n';
prompt += '      "longTailVariations": ["variation1", "variation2"],\n';
prompt += '      "contentIdea": "Blog post or page idea for this keyword"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "strategy": "Overall keyword strategy recommendation",\n';
prompt += '  "quickWins": ["keyword1", "keyword2"]\n';
prompt += '}';
return { prompt: prompt };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { keywords: [], strategy: raw, quickWins: [] }; }

var ai = $.steps.parseAI.output;
var keywords = ai.keywords || [];
var topKeywords = keywords.slice(0, 5).map(function(k) { return k.keyword; });
var query = topKeywords.join(' OR ') + ' ' + $.input.businessNiche;
return { query: query, topKeywords: topKeywords };

var ai = $.steps.parseAI.output;
var keywords = ai.keywords || [];
var exaResults = $.steps.validateWithExa.response.results || [];
var competitorUrls = exaResults.map(function(r) { return r.url || ''; });
var date = new Date().toISOString().split('T')[0];
var sheetData = keywords.map(function(k, i) {
  return {
    'Priority': k.priority || (i + 1),
    'Keyword': k.keyword || '',
    'Intent': k.intent || '',
    'Difficulty': k.difficulty || '',
    'Traffic Potential': k.trafficPotential || '',
    'Long-Tail Variations': (k.longTailVariations || []).join('; '),
    'Content Idea': (k.contentIdea || '').slice(0, 200),
    'Business Niche': $.input.businessNiche,
    'Date Generated': date
  };
});
return { sheetData: sheetData, keywordCount: keywords.length, strategy: ai.strategy || '', quickWins: ai.quickWins || [], topCompetitorUrls: competitorUrls.slice(0, 5), date: date };
